// Load sample deals for manual testing.
// Replace with real CRM export or Sheets read in production.
const sampleDeals = [
  { deal_id: 'D001', company: 'Globex Corp', segment: 'enterprise', outcome: 'won', acv: 24000, close_reason: 'Best integration with existing stack', primary_competitor: 'CompetitorA', deal_notes: 'Champion was CTO. Key decision: API flexibility. Trial lasted 3 weeks.' },
  { deal_id: 'D002', company: 'Initech LLC', segment: 'smb', outcome: 'lost', acv: 3600, close_reason: 'Price too high vs CompetitorB', primary_competitor: 'CompetitorB', deal_notes: 'Budget was fixed at $250/mo. Could not match discount. No exec sponsor.' },
  { deal_id: 'D003', company: 'Umbrella Ltd', segment: 'mid-market', outcome: 'won', acv: 12000, close_reason: 'Better onboarding and support SLA', primary_competitor: 'CompetitorA', deal_notes: 'Previous vendor had slow support. Onboarding team mentioned 3 times in notes.' },
  { deal_id: 'D004', company: 'Hooli Inc', segment: 'enterprise', outcome: 'lost', acv: 60000, close_reason: 'Missing SSO and SOC 2 Type II at time of eval', primary_competitor: 'CompetitorC', deal_notes: 'Security review took 6 weeks. We failed 2 of 8 requirements. CompetitorC is SOC2 certified.' },
  { deal_id: 'D005', company: 'Pied Piper', segment: 'startup', outcome: 'won', acv: 1200, close_reason: 'Free trial converted — no sales touch needed', primary_competitor: null, deal_notes: 'Self-serve signup. Upgraded after 14 days.' },
  { deal_id: 'D006', company: 'Dunder Mifflin', segment: 'smb', outcome: 'lost', acv: 4800, close_reason: 'Went with incumbent tool they already knew', primary_competitor: 'CompetitorB', deal_notes: 'No compelling event. Status quo won. POC was not decision maker.' },
  { deal_id: 'D007', company: 'Vandelay Ind', segment: 'mid-market', outcome: 'won', acv: 9600, close_reason: 'Reporting features superior to alternatives', primary_competitor: 'CompetitorA', deal_notes: 'Ran a bake-off. Our reporting module was decisive. Deal closed in 2 weeks.' },
  { deal_id: 'D008', company: 'Sterling Cooper', segment: 'enterprise', outcome: 'lost', acv: 36000, close_reason: 'Price too high vs CompetitorC', primary_competitor: 'CompetitorC', deal_notes: 'CompetitorC offered 40% year-1 discount. We were $15k over budget.' },
  { deal_id: 'D009', company: 'Wernham Hogg', segment: 'smb', outcome: 'won', acv: 2400, close_reason: 'Ease of use cited repeatedly', primary_competitor: 'CompetitorB', deal_notes: 'Non-technical buyer. Our UI simplicity was the key differentiator.' },
  { deal_id: 'D010', company: '', segment: 'startup', outcome: 'lost', acv: null, close_reason: '', primary_competitor: null, deal_notes: 'incomplete record — edge case' }
];
return sampleDeals.map(d => ({ json: d }));

// Filter and normalise deal records. Skip incomplete edge-case records.
const items = $input.all().map(i => i.json);
const valid = [];
const skipped = [];

for (const d of items) {
  if (!d.deal_id || !d.outcome || !d.segment) {
    skipped.push({ id: d.deal_id || 'unknown', reason: 'missing required fields' });
    continue;
  }
  if (!['won', 'lost'].includes(String(d.outcome).toLowerCase())) {
    skipped.push({ id: d.deal_id, reason: `unknown outcome: ${d.outcome}` });
    continue;
  }
  valid.push({
    deal_id: String(d.deal_id).trim(),
    company: String(d.company || 'Unknown').trim(),
    segment: String(d.segment || 'unknown').toLowerCase().trim(),
    outcome: String(d.outcome).toLowerCase().trim(),
    acv: Number(d.acv) || 0,
    close_reason: String(d.close_reason || '').trim(),
    primary_competitor: d.primary_competitor ? String(d.primary_competitor).trim() : null,
    deal_notes: String(d.deal_notes || '').substring(0, 500)
  });
}

console.log(`Validated: ${valid.length} deals, skipped: ${skipped.length}`);
// Return all valid deals as one aggregated item for the LLM
return [{ json: { deals: valid, skipped_count: skipped.length, total: valid.length + skipped.length } }];

const { deals, skipped_count, total } = $input.first().json;
const won = deals.filter(d => d.outcome === 'won');
const lost = deals.filter(d => d.outcome === 'lost');
const dealsJson = JSON.stringify(deals, null, 2);

const system = `You are a sales analyst specializing in win/loss analysis. You identify patterns across deal records, not individual anecdotes. You group by segment and competitor. Return ONLY valid JSON.`;

const user = `Analyze these ${deals.length} closed deals (${won.length} won, ${lost.length} lost) and identify recurring patterns.

Deal data:
${dealsJson}

Return JSON with this exact structure:
{
  "win_themes": [
    {
      "theme": "string — the pattern (e.g. 'Integration flexibility wins enterprise deals')",
      "frequency": number,
      "segments": ["string"],
      "evidence_deal_ids": ["string"],
      "confidence": "low|medium|high"
    }
  ],
  "loss_themes": [
    {
      "theme": "string",
      "frequency": number,
      "segments": ["string"],
      "evidence_deal_ids": ["string"],
      "confidence": "low|medium|high"
    }
  ],
  "competitor_analysis": [
    {
      "competitor": "string",
      "win_rate_vs_them": number,
      "deals_competed": number,
      "why_we_win": "string",
      "why_we_lose": "string"
    }
  ],
  "segment_breakdown": [
    {
      "segment": "string",
      "total_deals": number,
      "won": number,
      "lost": number,
      "win_rate_pct": number,
      "top_win_reason": "string",
      "top_loss_reason": "string"
    }
  ],
  "recommended_actions": [
    { "action": "string", "priority": "high|medium|low", "rationale": "string" }
  ],
  "data_quality_notes": ["string"]
}`;

return [{ json: { deals, skipped_count, total, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Analysis Prompt').first().json;
let parsed;
try {
  const content = response.choices?.[0]?.message?.content;
  if (!content) throw new Error('No content from LLM');
  parsed = JSON.parse(content);
} catch (e) {
  return [{ json: { _error: true, reason: `Parse failed: ${e.message}` } }];
}
const required = ['win_themes', 'loss_themes', 'competitor_analysis', 'segment_breakdown', 'recommended_actions'];
const missing = required.filter(k => !parsed[k] || !Array.isArray(parsed[k]));
if (missing.length > 0) {
  return [{ json: { _error: true, reason: `Missing arrays: ${missing.join(', ')}` } }];
}
return [{ json: { _error: false, analysis: parsed, meta: { total_deals: upstream.total, skipped: upstream.skipped_count, run_at: new Date().toISOString() } } }];

const { analysis, meta } = $input.first().json;
const fmt = (arr, fn) => (arr || []).map(fn).join('\n');

const winList = fmt(analysis.win_themes, t => `  [${t.confidence.toUpperCase()}] ${t.theme} (${t.frequency}x, segments: ${t.segments.join(', ')})`);
const lossList = fmt(analysis.loss_themes, t => `  [${t.confidence.toUpperCase()}] ${t.theme} (${t.frequency}x, segments: ${t.segments.join(', ')})`);
const compList = fmt(analysis.competitor_analysis, c => `  ${c.competitor}: win rate ${c.win_rate_vs_them}% in ${c.deals_competed} deals\n    Win: ${c.why_we_win}\n    Lose: ${c.why_we_lose}`);
const segList = fmt(analysis.segment_breakdown, s => `  ${s.segment}: ${s.won}W/${s.lost}L (${s.win_rate_pct}%) | Win: ${s.top_win_reason} | Loss: ${s.top_loss_reason}`);
const actionList = fmt(analysis.recommended_actions, a => `  [${a.priority.toUpperCase()}] ${a.action} — ${a.rationale}`);

const report = [
  `WIN/LOSS ANALYSIS REPORT`,
  `Deals analysed: ${meta.total_deals} (${meta.skipped} skipped due to incomplete data)`,
  `Run: ${meta.run_at}`,
  ``,
  `WIN THEMES`,
  winList || '  (none identified)',
  ``,
  `LOSS THEMES`,
  lossList || '  (none identified)',
  ``,
  `COMPETITOR ANALYSIS`,
  compList || '  (no competitor data)',
  ``,
  `SEGMENT BREAKDOWN`,
  segList || '  (no segment data)',
  ``,
  `RECOMMENDED ACTIONS`,
  actionList || '  (none)',
].join('\n');

return [{ json: { ...($input.first().json), report_text: report } }];
